1	-------------------------------------------------------------------------------
2	-- Title      : SSI Protocol: https://confluence.slac.stanford.edu/x/0oyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: SSI Package File
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_unsigned.all;
20	use ieee.std_logic_arith.all;
21	
22	
23	library surf;
24	use surf.StdRtlPkg.all;
25	use surf.AxiStreamPkg.all;
26	
27	package SsiPkg is
28	
29	   constant SSI_EOFE_C : natural := 0;
30	   constant SSI_SOF_C  : natural := 1;
31	
32	   constant SSI_TUSER_BITS_C : positive := 2;
33	   constant SSI_TDEST_BITS_C : positive := 4;
34	   constant SSI_TID_BITS_C   : natural  := 0;
35	   constant SSI_TSTRB_EN_C   : boolean  := false;
36	
37	   constant SSI_MASTER_FORCE_EOFE_C : AxiStreamMasterType := (
38	      tValid => '1',                    -- Force
39	      tData  => (others => '0'),
40	      tStrb  => (others => '1'),
41	      tKeep  => (others => '1'),
42	      tLast  => '1',                    -- EOF
43	      tDest  => (others => '0'),
44	      tId    => (others => '0'),
45	      tUser  => (others => '1'));       -- EOFE
46	
47	   -------------------------------------------------------------------------------------------------
48	   -- Build an SSI configuration
49	   -------------------------------------------------------------------------------------------------
50	   function ssiAxiStreamConfig (
51	      dataBytes : positive;
52	      tKeepMode : TKeepModeType         := TKEEP_COMP_C;
53	      tUserMode : TUserModeType         := TUSER_FIRST_LAST_C;
54	      tDestBits : natural range 0 to 8  := SSI_TDEST_BITS_C;
55	      tUserBits : positive range 2 to 8 := SSI_TUSER_BITS_C;
56	      tIdBits   : natural range 0 to 8  := SSI_TID_BITS_C)
57	      return AxiStreamConfigType;
58	
59	   -- A default SSI config is useful to have
60	   constant SSI_CONFIG_INIT_C : AxiStreamConfigType := ssiAxiStreamConfig(16);
61	
62	   -------------------------------------------------------------------------------------------------
63	   -- SSI Records and AXI-Stream conversion functions
64	   -------------------------------------------------------------------------------------------------
65	   type SsiMasterType is record
66	      valid  : sl;
67	      data   : slv(AXI_STREAM_MAX_TDATA_WIDTH_C-1 downto 0);
68	      strb   : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
69	      keep   : slv(AXI_STREAM_MAX_TKEEP_WIDTH_C-1 downto 0);
70	      dest   : slv(SSI_TDEST_BITS_C-1 downto 0);
71	      packed : sl;
72	      sof    : sl;
73	      eof    : sl;
74	      eofe   : sl;
75	   end record SsiMasterType;
76	
77	   type SsiSlaveType is record
78	      ready    : sl;
79	      pause    : sl;
80	      overflow : sl;
81	   end record SsiSlaveType;
82	
83	   function ssi2AxisMaster (
84	      axisConfig : AxiStreamConfigType;
85	      ssiMaster  : SsiMasterType)
86	      return AxiStreamMasterType;
87	
88	   function ssi2AxisSlave (
89	      ssiSlave : SsiSlaveType)
90	      return AxiStreamSlaveType;
91	
92	   function ssi2AxisCtrl (
93	      ssiSlave : SsiSlaveType)
94	      return AxiStreamCtrlType;
95	
96	   function axis2SsiMaster (
97	      axisConfig : AxiStreamConfigType;
98	      axisMaster : AxiStreamMasterType)
99	      return SsiMasterType;
100	
101	   function axis2SsiSlave (
102	      axisConfig : AxiStreamConfigType;
103	      axisSlave  : AxiStreamSlaveType := AXI_STREAM_SLAVE_INIT_C;
104	      axisCtrl   : AxiStreamCtrlType  := AXI_STREAM_CTRL_UNUSED_C)
105	      return SsiSlaveType;
106	
107	   function ssiMasterInit (
108	      axisConfig : AxiStreamConfigType)
109	      return SsiMasterType;
110	
111	   function ssiSlaveInit (
112	      axisConfig : AxiStreamConfigType)
113	      return SsiSlaveType;
114	
115	--   constant SSI_MASTER_INIT_C : SsiMasterType := axis2SsiMaster(SSI_CONFIG_INIT_C, AXI_STREAM_MASTER_INIT_C);
116	--   constant SSI_SLAVE_INIT_C  : SsiSlaveType  := axis2SsiSlave(AXI_STREAM_SLAVE_INIT_C, AXI_STREAM_CTRL_UNUSED_C);
117	
118	
119	   -------------------------------------------------------------------------------------------------
120	   -- Functions to interpret TUSER bits
121	   -------------------------------------------------------------------------------------------------
122	   function ssiGetUserEofe (
123	      axisConfig : AxiStreamConfigType;
124	      axisMaster : AxiStreamMasterType)
125	      return sl;
126	
127	   procedure ssiSetUserEofe (
128	      axisConfig : in    AxiStreamConfigType;
129	      axisMaster : inout AxiStreamMasterType;
130	      eofe       : in    sl);
131	
132	   function ssiGetUserSof (
133	      axisConfig : AxiStreamConfigType;
134	      axisMaster : AxiStreamMasterType)
135	      return sl;
136	
137	   procedure ssiSetUserSof (
138	      axisConfig : in    AxiStreamConfigType;
139	      axisMaster : inout AxiStreamMasterType;
140	      sof        : in    sl);
141	
142	   procedure ssiResetFlags (
143	      axisMaster : inout AxiStreamMasterType);
144	
145	end package SsiPkg;
146	
147	package body SsiPkg is
148	
149	   function ssiAxiStreamConfig (
150	      dataBytes : positive;
151	      tKeepMode : TKeepModeType         := TKEEP_COMP_C;
152	      tUserMode : TUserModeType         := TUSER_FIRST_LAST_C;
153	      tDestBits : natural range 0 to 8  := SSI_TDEST_BITS_C;
154	      tUserBits : positive range 2 to 8 := SSI_TUSER_BITS_C;
155	      tIdBits   : natural range 0 to 8  := SSI_TID_BITS_C)
156	      return AxiStreamConfigType is
157	      variable ret : AxiStreamConfigType;
158	   begin
159	      ret.TDATA_BYTES_C := dataBytes;       -- Configurable data size
160	      ret.TUSER_BITS_C  := tUserBits;       -- 2 TUSER: EOFE, SOF
161	      ret.TDEST_BITS_C  := tDestBits;       -- 4 TDEST bits for VC
162	      ret.TID_BITS_C    := tIdBits;         -- Optional TID
163	      ret.TKEEP_MODE_C  := tKeepMode;       --
164	      ret.TSTRB_EN_C    := SSI_TSTRB_EN_C;  -- No TSTRB support in SSI
165	      ret.TUSER_MODE_C  := tUserMode;       -- User field valid on last only
166	      return ret;
167	   end function ssiAxiStreamConfig;
168	
169	   function ssiGetUserEofe (
170	      axisConfig : AxiStreamConfigType;
171	      axisMaster : AxiStreamMasterType)
172	      return sl is
173	      variable ret : sl;
174	   begin
175	      ret := axiStreamGetUserBit(axisConfig, axisMaster, SSI_EOFE_C);
176	      return ret;
177	   end function;
178	
179	   -------------------------------------------------------------------------------------------------
180	   function ssi2AxisMaster (
181	      axisConfig : AxiStreamConfigType;
182	      ssiMaster  : SsiMasterType)
183	      return AxiStreamMasterType
184	   is
185	      variable ret : AxiStreamMasterType;
186	   begin
187	      ret                                    := AXI_STREAM_MASTER_INIT_C;
188	      ret.tValid                             := ssiMaster.valid;
189	      ret.tData                              := ssiMaster.data;
190	      ret.tLast                              := ssiMaster.eof;
191	      ret.tStrb                              := ssiMaster.strb;
192	      ret.tKeep                              := ssiMaster.keep;
193	      ret.tDest(SSI_TDEST_BITS_C-1 downto 0) := ssiMaster.dest;
194	      ssiSetUserSof(axisConfig, ret, ssiMaster.sof);
195	      ssiSetUserEofe(axisConfig, ret, ssiMaster.eofe);
196	      return ret;
197	   end function ssi2AxisMaster;
198	
199	   function ssi2AxisSlave (
200	      ssiSlave : SsiSlaveType)
201	      return AxiStreamSlaveType
202	   is
203	      variable ret : AxiStreamSlaveType;
204	   begin
205	      ret.tReady := ssiSlave.ready;
206	      return ret;
207	   end function ssi2AxisSlave;
208	
209	   function ssi2AxisCtrl (
210	      ssiSlave : SsiSlaveType)
211	      return AxiStreamCtrlType
212	   is
213	      variable ret : AxiStreamCtrlType;
214	   begin
215	      ret.pause    := ssiSlave.pause;
216	      ret.overflow := ssiSlave.overflow;
217	      return ret;
218	   end function ssi2AxisCtrl;
219	
220	   function axis2SsiMaster (
221	      axisConfig : AxiStreamConfigType;
222	      axisMaster : AxiStreamMasterType)
223	      return SsiMasterType
224	   is
225	      variable ret : SsiMasterType;
226	   begin
227	      ret.valid  := axisMaster.tValid;
228	      ret.data   := axisMaster.tData;
229	      ret.strb   := axisMaster.tStrb;
230	      ret.keep   := axisMaster.tKeep;
231	      ret.packed := toSl(axiStreamPacked(axisConfig, axisMaster));
232	      ret.dest   := axisMaster.tDest(SSI_TDEST_BITS_C-1 downto 0);
233	      ret.sof    := ssiGetUserSof(axisConfig, axisMaster);
234	      ret.eof    := axisMaster.tLast;
235	      ret.eofe   := ssiGetUserEofe(axisConfig, axisMaster);
236	      return ret;
237	   end function axis2SsiMaster;
238	
239	   function axis2SsiSlave (
240	      axisConfig : AxiStreamConfigType;
241	      axisSlave  : AxiStreamSlaveType := AXI_STREAM_SLAVE_INIT_C;
242	      axisCtrl   : AxiStreamCtrlType  := AXI_STREAM_CTRL_UNUSED_C)
243	      return SsiSlaveType
244	   is
245	      variable ret : SsiSlaveType;
246	   begin
247	      ret.ready    := axisSlave.tReady;
248	      ret.pause    := axisCtrl.pause;
249	      ret.overflow := axisCtrl.overflow;
250	      return ret;
251	   end function axis2SsiSlave;
252	
253	   function ssiMasterInit (
254	      axisConfig : AxiStreamConfigType)
255	      return SsiMasterType is
256	      variable ret : SsiMasterType;
257	   begin
258	      ret      := axis2ssiMaster(axisConfig, AXI_STREAM_MASTER_INIT_C);
259	      ret.keep := genTKeep(axisConfig.TDATA_BYTES_C);
260	      return ret;
261	   end function ssiMasterInit;
262	
263	   function ssiSlaveInit (
264	      axisConfig : AxiStreamConfigType)
265	      return SsiSlaveType is
266	   begin
267	      return axis2ssiSlave(axisConfig, AXI_STREAM_SLAVE_INIT_C, AXI_STREAM_CTRL_UNUSED_C);
268	   end function ssiSlaveInit;
269	
270	
271	   -------------------------------------------------------------------------------------------------
272	   procedure ssiSetUserEofe (
273	      axisConfig : in    AxiStreamConfigType;
274	      axisMaster : inout AxiStreamMasterType;
275	      eofe       : in    sl) is
276	   begin
277	      axiStreamSetUserBit(axisConfig, axisMaster, SSI_EOFE_C, eofe);
278	   end procedure;
279	
280	   function ssiGetUserSof (
281	      axisConfig : AxiStreamConfigType;
282	      axisMaster : AxiStreamMasterType)
283	      return sl is
284	      variable ret : sl;
285	   begin
286	      ret := axiStreamGetUserBit(axisConfig, axisMaster, SSI_SOF_C, 0);
287	      return ret;
288	   end function;
289	
290	   procedure ssiSetUserSof (
291	      axisConfig : in    AxiStreamConfigType;
292	      axisMaster : inout AxiStreamMasterType;
293	      sof        : in    sl) is
294	   begin
295	      axiStreamSetUserBit(axisConfig, axisMaster, SSI_SOF_C, sof, 0);
296	   end procedure;
297	
298	   procedure ssiResetFlags (
299	      axisMaster : inout AxiStreamMasterType) is
300	   begin
301	      axisMaster.tValid := '0';
302	      axisMaster.tLast  := '0';
303	      axisMaster.tUser  := (others => '0');
304	   end procedure;
305	
306	end package body SsiPkg;
307

