1	-------------------------------------------------------------------------------
2	-- Title      : RSSI Protocol: https://confluence.slac.stanford.edu/x/1IyfD
3	-------------------------------------------------------------------------------
4	-- Company    : SLAC National Accelerator Laboratory
5	-------------------------------------------------------------------------------
6	-- Description: RSSI Package File
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.SsiPkg.all;
24	use surf.AxiStreamPkg.all;
25	
26	package RssiPkg is
27	
28	   --------------------------------------------------------------------------
29	   -- Common constant definitions
30	   --------------------------------------------------------------------------
31	   constant RSSI_WORD_WIDTH_C  : positive := 8;  -- 64 bit word (FIXED)
32	   constant RSSI_AXIS_CONFIG_C : AxiStreamConfigType :=
33	      ssiAxiStreamConfig(
34	         dataBytes => RSSI_WORD_WIDTH_C,
35	         tKeepMode => TKEEP_COMP_C,
36	         tUserMode => TUSER_FIRST_LAST_C,
37	         tDestBits => 0,
38	         tUserBits => 2);
39	
40	   -- Header sizes
41	   constant SYN_HEADER_SIZE_C  : natural := 24;
42	   constant ACK_HEADER_SIZE_C  : natural := 8;
43	   constant EACK_HEADER_SIZE_C : natural := 8;
44	   constant RST_HEADER_SIZE_C  : natural := 8;
45	   constant NULL_HEADER_SIZE_C : natural := 8;
46	   constant DATA_HEADER_SIZE_C : natural := 8;
47	
48	   --------------------------------------------------------------------------
49	   -- Sub-types
50	   --------------------------------------------------------------------------
51	   type RssiParamType is record
52	      version     : slv(3 downto 0);
53	      chksumEn    : slv(0 downto 0);
54	      timeoutUnit : slv(7 downto 0);
55	
56	      maxOutsSeg : slv(7 downto 0);     -- Receiver parameter
57	      maxSegSize : slv(15 downto 0);    -- Receiver parameter
58	
59	      retransTout  : slv(15 downto 0);
60	      cumulAckTout : slv(15 downto 0);
61	      nullSegTout  : slv(15 downto 0);
62	
63	      maxRetrans : slv(7 downto 0);
64	      maxCumAck  : slv(7 downto 0);
65	
66	      maxOutofseq : slv(7 downto 0);
67	
68	      connectionId : slv(31 downto 0);
69	   end record RssiParamType;
70	
71	   constant RSSI_PARAM_INIT_C : RssiParamType := (
72	      version      => (others => '0'),
73	      chksumEn     => (others => '0'),
74	      timeoutUnit  => (others => '0'),
75	      maxOutsSeg   => (others => '0'),
76	      maxSegSize   => (others => '0'),
77	      retransTout  => (others => '0'),
78	      cumulAckTout => (others => '0'),
79	      nullSegTout  => (others => '0'),
80	      maxRetrans   => (others => '0'),
81	      maxCumAck    => (others => '0'),
82	      maxOutofseq  => (others => '0'),
83	      connectionId => (others => '0'));
84	
85	   type flagsType is record
86	      syn  : sl;
87	      ack  : sl;
88	      eack : sl;
89	      rst  : sl;
90	      nul  : sl;
91	      data : sl;
92	      busy : sl;
93	      eofe : sl;
94	   end record flagsType;
95	
96	   type WindowType is record
97	      seqN     : slv(7 downto 0);
98	      segType  : slv(2 downto 0);
99	      keep     : slv(RSSI_WORD_WIDTH_C-1 downto 0);
100	      segSize  : natural;
101	      occupied : sl;
102	   end record WindowType;
103	
104	   constant WINDOW_INIT_C : WindowType := (
105	      seqN     => (others => '0'),
106	      segType  => (others => '0'),
107	      keep     => (others => '1'),
108	      segSize  => 0,
109	      occupied => '0');
110	
111	   -- Arrays
112	   type WindowTypeArray is array (natural range<>) of WindowType;
113	
114	   --------------------------------------------------------------------------
115	   -- Function declarations
116	   --------------------------------------------------------------------------
117	   -- Swap little and big endians
118	   -- 64-bit header word
119	   function endianSwap64(data_slv : slv(63 downto 0)) return std_logic_vector;
120	
121	end RssiPkg;
122	
123	package body RssiPkg is
124	
125	   --------------------------------------------------------------------------
126	   -- Function bodies
127	   --------------------------------------------------------------------------
128	   -- Swap little or big endians 64-bit header
129	   function endianSwap64(data_slv : slv(63 downto 0)) return std_logic_vector is
130	      variable vSlv : slv(63 downto 0);
131	   begin
132	      vSlv := (others => '0');
133	
134	      for i in 7 downto 0 loop
135	         vSlv((8*(7-i))+7 downto 8*(7-i)) := data_slv((8*i)+7 downto 8*i);
136	      end loop;
137	
138	      return vSlv;
139	
140	   end endianSwap64;
141	--------------------------------------------------------------------------------------------
142	end package body RssiPkg;
143

