37	         tKeepMode => TKEEP_COMP_C,
38	         tUserMode => TUSER_FIRST_LAST_C,
39	         tDestBits => 4,
40	         tUserBits => 2);
41	
42	   -- Define K code BTFs
43	   constant PGP3_IDLE_C : slv(7 downto 0)   := X"99";
44	   constant PGP3_SOF_C  : slv(7 downto 0)   := X"AA";
45	   constant PGP3_EOF_C  : slv(7 downto 0)   := X"55";
46	   constant PGP3_SOC_C  : slv(7 downto 0)   := X"CC";
47	   constant PGP3_EOC_C  : slv(7 downto 0)   := X"33";
48	   constant PGP3_SKP_C  : slv(7 downto 0)   := X"66";
49	   constant PGP3_USER_C : Slv8Array(0 to 7) := (X"78", X"87", X"2D", X"D2", X"1E", X"E1", X"B4", X"4B");
50	
51	   constant PGP3_VALID_BTF_ARRAY_C : Slv8Array := (
52	      0  => PGP3_IDLE_C,
53	      1  => PGP3_SOF_C,
54	      2  => PGP3_EOF_C,
55	      3  => PGP3_SOC_C,
56	      4  => PGP3_EOC_C,
57	      5  => PGP3_SKP_C,
58	      6  => PGP3_USER_C(0),
59	      7  => PGP3_USER_C(1),
60	      8  => PGP3_USER_C(2),
61	      9  => PGP3_USER_C(3),
62	      10 => PGP3_USER_C(4),
63	      11 => PGP3_USER_C(5),
64	      12 => PGP3_USER_C(6),
65	      13 => PGP3_USER_C(7));
66	
67	   constant PGP3_D_HEADER_C : slv(1 downto 0) := "01";
68	   constant PGP3_K_HEADER_C : slv(1 downto 0) := "10";
69	
70	   constant PGP3_SCRAMBLER_TAPS_C : IntegerArray(0 to 1) := (0 => 39, 1 => 58);
71	
72	   subtype PGP3_BTF_FIELD_C is natural range 63 downto 56;
73	   subtype PGP3_LINKINFO_FIELD_C is natural range 39 downto 0;
74	   subtype PGP3_SOFC_VC_FIELD_C is natural range 43 downto 40;
75	   subtype PGP3_SOFC_SEQ_FIELD_C is natural range 55 downto 44;
76	   subtype PGP3_EOFC_TUSER_FIELD_C is natural range 7 downto 0;
77	   subtype PGP3_EOFC_BYTES_LAST_FIELD_C is natural range 19 downto 16;
78	   subtype PGP3_EOFC_CRC_FIELD_C is natural range 55 downto 24;
79	   subtype PGP3_USER_CHECKSUM_FIELD_C is natural range 55 downto 48;
80	   subtype PGP3_USER_OPCODE_FIELD_C is natural range 47 downto 0;
81	   subtype PGP3_SKIP_DATA_FIELD_C is natural range 55 downto 0;
82	
83	   constant PGP3_CRC_POLY_C : slv(31 downto 0) := X"04C11DB7";
84	
85	   function pgp3MakeLinkInfo (
86	      locRxFifoCtrl  : AxiStreamCtrlArray;
87	      locRxLinkReady : sl)
88	      return slv;
89	
90	   procedure pgp3ExtractLinkInfo (
91	      linkInfo       : in    slv(39 downto 0);
92	      remRxFifoCtrl  : inout AxiStreamCtrlArray;
93	      remRxLinkReady : inout sl;
94	      version        : inout slv(2 downto 0));
95	
96	   function pgp3OpCodeChecksum (
97	      opCodeData : slv(47 downto 0))
98	      return slv;
