100	
101	   type Pgp3TxInType is record
102	      disable      : sl;
103	      flowCntlDis  : sl;
104	      resetTx      : sl;
105	      skpInterval  : slv(31 downto 0);
106	      opCodeEn     : sl;
107	      opCodeNumber : slv(2 downto 0);
108	      opCodeData   : slv(47 downto 0);
109	      locData      : slv(55 downto 0);
110	   end record Pgp3TxInType;
111	
112	   type Pgp3TxInArray is array (natural range<>) of Pgp3TxInType;
113	
114	   constant PGP3_TX_IN_INIT_C : Pgp3TxInType := (
115	      disable      => '0',
116	      flowCntlDis  => '0',
117	      resetTx      => '0',
118	      skpInterval  => toSlv(5000, 32),
119	      opCodeEn     => '0',
120	      opCodeNumber => (others => '0'),
121	      opCodeData   => (others => '0'),
122	      locData      => (others => '0'));
123	
124	
125	   type Pgp3TxOutType is record
126	      locOverflow : slv(15 downto 0);
127	      locPause    : slv(15 downto 0);
128	      phyTxActive : sl;
129	      linkReady   : sl;
130	      opCodeReady : sl;
131	      frameTx     : sl;                 -- A good frame was transmitted
132	      frameTxErr  : sl;                 -- An errored frame was transmitted
133	   end record;
134	
135	   type Pgp3TxOutArray is array (natural range<>) of Pgp3TxOutType;
136	
137	   constant PGP3_TX_OUT_INIT_C : Pgp3TxOutType := (
138	      locOverflow => (others => '0'),
139	      locPause    => (others => '0'),
140	      phyTxActive => '0',
141	      linkReady   => '0',
142	      opCodeReady => '0',
143	      frameTx     => '0',
144	      frameTxErr  => '0');
145	
146	   type Pgp3RxInType is record
147	      loopback : slv(2 downto 0);
148	      resetRx  : sl;
149	   end record Pgp3RxInType;
150	
151	   type Pgp3RxInArray is array (natural range<>) of Pgp3RxInType;
152	
153	   constant PGP3_RX_IN_INIT_C : Pgp3RxInType := (
154	      loopback => (others => '0'),
155	      resetRx  => '0');
156	
157	
158	   type Pgp3RxOutType is record
159	      phyRxActive    : sl;
160	      linkReady      : sl;                -- locRxLinkReady
161	      frameRx        : sl;                -- A good frame was received
162	      frameRxErr     : sl;                -- An errored frame was received
163	      cellError      : sl;                -- A cell error has occurred
164	      linkDown       : sl;                -- A link down event has occurred
165	      linkError      : sl;                -- A link error has occurred
166	      opCodeEn       : sl;                -- Opcode valid
167	      opCodeNumber   : slv(2 downto 0);   -- Opcode number
168	      opCodeData     : slv(47 downto 0);  -- Opcode data
169	      remLinkData    : slv(55 downto 0);  -- Far end side User Data
170	      remRxLinkReady : sl;                -- Far end RX has link
171	      remRxOverflow  : slv(15 downto 0);  -- Far end RX overflow status
172	      remRxPause     : slv(15 downto 0);  -- Far end pause status
173	
174	      phyRxData   : slv(63 downto 0);
175	      phyRxHeader : slv(1 downto 0);
176	      phyRxValid  : sl;
177	      phyRxInit   : sl;
178	
179	      gearboxAligned : sl;
180	
181	      ebData     : slv(63 downto 0);
182	      ebHeader   : slv(1 downto 0);
183	      ebValid    : sl;
184	      ebOverflow : sl;
185	      ebStatus   : slv(8 downto 0);
186	   end record Pgp3RxOutType;
187	
188	   type Pgp3RxOutArray is array (natural range<>) of Pgp3RxOutType;
189	
190	   constant PGP3_RX_OUT_INIT_C : Pgp3RxOutType := (
191	      phyRxActive    => '0',
192	      linkReady      => '0',
193	      frameRx        => '0',
194	      frameRxErr     => '0',
195	      cellError      => '0',
196	      linkDown       => '0',
197	      linkError      => '0',
198	      opCodeEn       => '0',
199	      opCodeNumber   => (others => '0'),
200	      opCodeData     => (others => '0'),
201	      remLinkData    => (others => '0'),
202	      remRxLinkReady => '0',
203	      remRxOverflow  => (others => '0'),
204	      remRxPause     => (others => '0'),
205	      phyRxData      => (others => '0'),
206	      phyRxHeader    => (others => '0'),
207	      phyRxValid     => '0',
208	      phyRxInit      => '0',
209	      gearboxAligned => '0',
210	      ebData         => (others => '0'),
211	      ebHeader       => (others => '0'),
212	      ebValid        => '0',
213	      ebOverflow     => '0',
214	      ebStatus       => (others => '0'));
215	
216	end package Pgp3Pkg;
217	
218	package body Pgp3Pkg is
219	
220	   function pgp3MakeLinkInfo (
221	      locRxFifoCtrl  : AxiStreamCtrlArray;
222	      locRxLinkReady : sl)
223	      return slv
224	   is
225	      variable ret : slv(39 downto 0) := (others => '0');
226	   begin
227	      for i in locRxFifoCtrl'range loop
228	         ret(i)    := locRxFifoCtrl(i).pause;
229	         ret(i+16) := locRxFifoCtrl(i).overflow;
230	      end loop;
231	      ret(32)           := locRxLinkReady;
232	      ret(35 downto 33) := PGP3_VERSION_C;
233	      return ret;
234	   end function;
235	
236	   procedure pgp3ExtractLinkInfo (
237	      linkInfo       : in    slv(39 downto 0);
238	      remRxFifoCtrl  : inout AxiStreamCtrlArray;
239	      remRxLinkReady : inout sl;
240	      version        : inout slv(2 downto 0)) is
241	   begin
242	      for i in remRxFifoCtrl'range loop
243	         remRxFifoCtrl(i).pause    := linkInfo(i);
244	         remRxFifoCtrl(i).overflow := linkInfo(i+16);
245	      end loop;
246	      remRxLinkReady := linkInfo(32);
247	      version        := linkInfo(35 downto 33);
248	   end procedure;
249	
250	   function pgp3OpCodeChecksum (
251	      opCodeData : slv(47 downto 0))
252	      return slv
253	   is
254	      variable ret : slv(7 downto 0);
255	   begin
256	      ret := not (opCodeData(7 downto 0) +
257	                  opCodeData(15 downto 8) +
258	                  opCodeData(23 downto 16) +
259	                  opCodeData(31 downto 24) +
260	                  opCodeData(39 downto 32) +
261	                  opCodeData(47 downto 40));
262	      return ret;
263	   end function;
264	
265	end package body Pgp3Pkg;
