42	   constant PGP4_IDLE_C : slv(7 downto 0) := X"99";
43	   constant PGP4_SOF_C  : slv(7 downto 0) := X"AA";
44	   constant PGP4_EOF_C  : slv(7 downto 0) := X"55";
45	   constant PGP4_SOC_C  : slv(7 downto 0) := X"CC";
46	   constant PGP4_EOC_C  : slv(7 downto 0) := X"33";
47	   constant PGP4_SKP_C  : slv(7 downto 0) := X"66";
