50	   constant PGP4_VALID_BTF_ARRAY_C : Slv8Array := (
51	      0 => PGP4_IDLE_C,
52	      1 => PGP4_SOF_C,
53	      2 => PGP4_EOF_C,
54	      3 => PGP4_SOC_C,
55	      4 => PGP4_EOC_C,
56	      5 => PGP4_SKP_C,
57	      6 => PGP4_USER_C);
