63	
64	   subtype PGP4_BTF_FIELD_C is natural range 63 downto 56;
65	   subtype PGP4_K_CODE_CRC_FIELD_C is natural range 55 downto 48;
66	   subtype PGP4_SKIP_DATA_FIELD_C is natural range 47 downto 0;
67	   subtype PGP4_USER_OPCODE_FIELD_C is natural range 47 downto 0;
68	
69	   subtype PGP4_LINKINFO_FIELD_C is natural range 31 downto 0;
70	   subtype PGP4_SOFC_VC_FIELD_C is natural range 35 downto 32;
71	   subtype PGP4_SOFC_SEQ_FIELD_C is natural range 47 downto 36;
