88	      linkInfo       : in    slv(PGP4_LINKINFO_FIELD_C);
89	      remRxFifoCtrl  : inout AxiStreamCtrlArray;
90	      remRxLinkReady : inout sl;
91	      version        : inout slv(7 downto 0));
