98	      disable     : sl;
99	      flowCntlDis : sl;
100	      resetTx     : sl;
101	      skpInterval : slv(31 downto 0);
102	      opCodeEn    : sl;
103	      opCodeData  : slv(47 downto 0);
104	      locData     : slv(47 downto 0);
105	   end record Pgp4TxInType;
