183	      1 => (MakeI2cAxiLiteDevType("0000010", 16, 16, '0')),
184	      2 => (MakeI2cAxiLiteDevType("0000100", 32, 8, '0')),
185	      3 => (MakeI2cAxiLiteDevType("0001000", 32, 32, '0')));
186	
