190	   -- Opencores i2c
191	   component i2c_master_byte_ctrl is
192	      generic (
193	         FILTER  : integer;
194	         DYNFILT : integer);
195	      port (
196	         clk    : in std_logic;
197	         rst    : in std_logic;         -- active high reset
198	         nReset : in std_logic;         -- asynchornous active low reset
199	         -- (not used in GRLIB)
200	         ena    : in std_logic;         -- core enable signal
201	
202	         clk_cnt : in std_logic_vector(15 downto 0);  -- 4x SCL
203	
204	         -- input signals
205	         start  : in std_logic;
206	         stop   : in std_logic;
207	         read   : in std_logic;
208	         write  : in std_logic;
209	         ack_in : in std_logic;
210	         din    : in std_logic_vector(7 downto 0);
211	         filt   : in std_logic_vector((FILTER-1)*DYNFILT downto 0);
212	
213	         -- output signals
214	         cmd_ack  : out std_logic;
215	         ack_out  : out std_logic;
216	         i2c_busy : out std_logic;
217	         i2c_al   : out std_logic;
218	         dout     : out std_logic_vector(7 downto 0);
219	
220	         -- i2c lines
221	         scl_i   : in  std_logic;       -- i2c clock line input
222	         scl_o   : out std_logic;       -- i2c clock line output
223	         scl_oen : out std_logic;   -- i2c clock line output enable, active low
224	         sda_i   : in  std_logic;       -- i2c data line input
225	         sda_o   : out std_logic;       -- i2c data line output
226	         sda_oen : out std_logic);  -- i2c data line output enable, active low
227	   end component i2c_master_byte_ctrl;
228	
229	end package I2cPkg;
230	
231	package body I2cPkg is
232	
233	   function MakeI2cAxiLiteDevType (
234	      i2cAddress  : slv;
235	      dataSize    : integer;
236	      addrSize    : integer;
237	      endianness  : sl;
238	      repeatStart : sl := '0')
239	      return I2cAxiLiteDevType
240	   is
241	      variable ret : I2cAxiLiteDevType;
242	   begin
243	      if (i2cAddress'length = 7) then
244	         ret.i2cAddress := "000" & i2cAddress;
245	         ret.i2cTenbit  := '0';
246	      elsif (i2cAddress'length = 10) then
247	         ret.i2cAddress := i2cAddress;
248	         ret.i2cTenbit  := '1';
249	      else
250	         report "i2cAddress param must have length of 7 or 10" severity failure;
251	      end if;
252	
253	      ret.dataSize    := dataSize;
254	      ret.addrSize    := addrSize;
255	      ret.endianness  := endianness;
256	      ret.repeatStart := repeatStart;
257	      return ret;
258	   end function MakeI2cAxiLiteDevType;
259	
260	   function maxAddrSize (constant devMap : I2cAxiLiteDevArray) return natural is
261	      variable ret : natural := 0;
262	   begin
263	      for i in devMap'range loop
264	         if (devMap(i).addrSize > ret) then
265	            ret := devMap(i).addrSize;
266	         end if;
267	      end loop;
268	      return ret;
269	   end function maxAddrSize;
270	
271	end package body I2cPkg;
